class Solution:
    def maximumLengthSubstring(self, s: str) -> int:
        from collections import defaultdict
        left = 0
        max_len = 0
        freq = defaultdict(int)
        for right, ch in enumerate(s):
            freq[ch] += 1
            while freq[ch] > 2:
                freq[s[left]] -= 1
                left += 1
            max_len = max(max_len, right - left + 1)
        return max_len
